package com.spendwise.prototype.ui; import android.view.*; import android.widget.TextView; import androidx.recyclerview.widget.*; import com.spendwise.prototype.R; import com.spendwise.prototype.data.Expense; import java.text.DateFormat; class ExpenseAdapter(val onClick:(Expense)->Unit):ListAdapter<Expense,ExpenseAdapter.VH>(Diff){ object Diff:DiffUtil.ItemCallback<Expense>(){ override fun areItemsTheSame(a:Expense,b:Expense)=a.id==b.id; override fun areContentsTheSame(a:Expense,b:Expense)=a==b }; inner class VH(v:View):RecyclerView.ViewHolder(v){ val d=v.findViewById<TextView>(R.id.tvDesc); val t=v.findViewById<TextView>(R.id.tvDate); val a=v.findViewById<TextView>(R.id.tvAmount) }; override fun onCreateViewHolder(p:ViewGroup,t:Int)=VH(LayoutInflater.from(p.context).inflate(R.layout.item_expense,p,false)); override fun onBindViewHolder(h:VH,pos:Int){ val e=getItem(pos); h.d.text=e.description; h.t.text=DateFormat.getDateInstance().format(e.dateMillis); h.a.text="R%.2f".format(e.amount); h.itemView.setOnClickListener{ onClick(e) } } }
